sys_script_include.script:
/**
 * @class Installer
 * @description 
 * @since 19/02/2026
 * @date  19/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class Installer {

    /**
     * constructor
     * 
     * @param _scope application scope
     */
    constructor(_source) {
        this.source = _source;
        this.LOG_HANDLER = new LoggingHandler();

		// var legacyMode = gs.getProperty('glide.record.legacy_cross_scope_access_policy_in_script');

		// if (UtilityFunctions.getBooleanValue(legacyMode) === false) {
		// 	this.LOG_HANDLER.fatal('x_984628_deploye_0.Installer', 'The system property' +
		// 		"glide.record.legacy_cross_scope_access_policy_in_script" +
		// 		'must be set to true during installation!');

		// 	throw new Error('Installation failed');
		// }


        this.LOG_HANDLER.hint(this.source, 'Installation started');
    }

    /**
     * Logs the end of the current source installation
     */
    finish() {
        this.LOG_HANDLER.hint(this.source, 'Installation finished');
    }

    /**
     * proxy function
	 * see RecordInserter#recordInsert()
     */
    recordInsert(reason, table, properties, stealth) {
        return new RecordInserter().recordInsert(this.source, reason, table, properties, stealth);
    }

    /**
     * proxy function
	 * see RecordUpdater#recordUpdate()
     */
    // eslint-disable-next-line
    recordUpdate(reason, table, sysId, field, value, stealth) {
        return new RecordUpdater().recordUpdate(this.source, reason, table, sysId, field, value, stealth);
    }

    /**
     * proxy function
	 * see RecordUpdater#recordUpdateByQuery()
     */
    // eslint-disable-next-line
    recordUpdateByQuery(reason, table, query, properties, stealth) {
        return new RecordUpdater().recordUpdateByQuery(this.source, reason, table, query, properties, stealth);
    }

    /**
     * proxy function
	 * see RecordDeleter#recordDelete()
     */
    recordDelete(reason, table, sysId, stealth) {
        return new RecordDeleter().recordDelete(this.source, reason, table, sysId, stealth);
    }

    /**
     * proxy function
	 * see RecordUpdater#dictionaryOverrideRecordUpdate()
     */
    // eslint-disable-next-line
    dictionaryOverrideRecordUpdate(reason, name, element, override, field, value, stealth) {
        return new RecordUpdater().dictionaryOverrideRecordUpdate(this.source, reason, name, element, 
			override, field, value, stealth);
    }

    /**
     * proxy function
	 * see RecordUpdater#dictionaryRecordUpdate()
     */
    // eslint-disable-next-line
    dictionaryRecordUpdate(reason, name, element, field, value, stealth) {
        return new RecordUpdater().dictionaryRecordUpdate(this.source, reason, name, 
			element, field, value, stealth);
    }

    /**
     * proxy function
	 * see RecordUpdater#recordUpdateValue()
     */
    // eslint-disable-next-line
	recordUpdateValue(reason, table, sysId, field, value, stealth) {
        return new RecordUpdater().recordUpdateValue(this.source, reason, table, 
			sysId, field, value, stealth);
	}

}
